sub extract_text {
    my ($pdf_file) = @_;

    # Open the PDF file
    my $pdf = PDF::API2->open($pdf_file);

    # Get the number of pages in the PDF
    my $pages = $pdf->pages;

    my $text = '';

    # Loop through each page
    for my $page (1 .. $pages) {
        # Get the page object
        my $page_obj = $pdf->page($page);

        # Extract text from the page
        $text .= $page_obj->text;
    }

    return $text;
}

